import{_ as i,c as a,o as e,aN as t}from"./chunks/framework.CqA5BTDU.js";const o=JSON.parse('{"title":"Redis 基础","description":"","frontmatter":{},"headers":[],"relativePath":"05.Redis/01-Redis基础.md","filePath":"05.Redis/01-Redis基础.md","lastUpdated":null}'),h={name:"05.Redis/01-Redis基础.md"};function n(l,s,p,k,d,r){return e(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="redis-基础" tabindex="-1">Redis 基础 <a class="header-anchor" href="#redis-基础" aria-label="Permalink to &quot;Redis 基础&quot;">​</a></h1><p>把经常访问的数据放到一个读写都很快的地方，是大多数 Web 应用绕不开的需求。没有 Redis 的时候，常见的做法是用数据库直接扛——MySQL 里建一张缓存表，或者应用内存里维护一个 HashMap。前者的瓶颈在磁盘 IO（即使是 SSD，随机读延迟也比内存高几个数量级）；后者的问题是进程重启数据就没了，多实例部署时各自维护一份、数据不一致。另一个场景是计数器、排行榜、分布式锁——关系数据库的行锁和磁盘写入延迟让这些操作在高并发下成本很高。</p><p>Redis 是一个内存中的键值数据库，所有数据常驻内存，因此读写延迟很低（通常亚毫秒级）。它不像关系数据库那样用表格和 SQL，而是直接操作键和值——值可以是字符串、哈希、列表、集合、有序集合等几种数据结构。</p><p>&quot;常驻内存&quot;意味着两件事：读写快，但数据量受物理内存限制。Redis 提供了持久化机制把数据保存到磁盘（RDB 快照和 AOF 日志），但内存仍然是数据的主存位置——磁盘文件只用于重启恢复，正常运行时不从磁盘读数据。</p><p>Redis 的单线程模型（指命令处理部分，6.0 之后 I/O 线程可以分担网络读写）避免了多线程对共享数据加锁的开销。每条命令在某个时刻只被一个操作处理，不会出现两个命令同时修改同一个键的场景。代价是：单条慢命令（比如对一个很大的集合做复杂的聚合运算）会堵住后面的所有请求。</p><h2 id="一、五类基本数据结构" tabindex="-1">一、五类基本数据结构 <a class="header-anchor" href="#一、五类基本数据结构" aria-label="Permalink to &quot;一、五类基本数据结构&quot;">​</a></h2><p>每种数据结构不是&quot;能存什么&quot;，而是&quot;数据的组织方式 + 针对这种组织方式能做什么操作&quot;。</p><h3 id="string——二进制安全的字节串" tabindex="-1">String——二进制安全的字节串 <a class="header-anchor" href="#string——二进制安全的字节串" aria-label="Permalink to &quot;String——二进制安全的字节串&quot;">​</a></h3><p>String 是 Redis 最底层的结构——整数、浮点数、JSON 文本、序列化后的对象，存进去都是字节串。单键单值，最大 512 MB。</p><p>&quot;二进制安全&quot;的意思是：Redis 不关心字节串里是什么内容，不会因为遇到 <code>\\0</code> 就截断，也不会尝试按某种字符编码去解析。存什么字节进去，取出来就是什么字节。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user:1001:name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;zhangsan&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">GET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user:1001:name</span></span></code></pre></div><p>计数操作用的是 <code>INCR</code>/<code>DECR</code>。因为单线程，对同一个 key 的 INCR 不存在&quot;读-改-写&quot;的竞争窗口——不需要事务包裹也能保证原子递增：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> article:1001:views</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">INCR</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> article:1001:views</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # -&gt; 1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">INCRBY</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> article:1001:views</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 一次加 10</span></span></code></pre></div><p><code>INCR</code> 要求值能解析为整数，对非数字字符串执行 <code>INCR</code> 会报错。</p><p>分布式锁常用 <code>SET ... NX EX</code>——只有 key 不存在时才写入并带上过期时间：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lock:order:1001</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;thread-5&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> NX</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> EX</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 30</span></span></code></pre></div><p><code>NX</code>（Not eXists）保证只有一个客户端能拿到锁，<code>EX 30</code> 保证即使拿到锁的客户端崩溃了，锁也会在 30 秒后自动释放，不会永久死锁。但释放锁时需要验证 value 是不是自己的——如果直接 <code>DEL</code>，可能把自己锁超时后别人拿到的锁删掉。这个校验和删除的两步操作需要用 Lua 脚本保证原子性（见下面 Lua 脚本部分）。</p><h3 id="hash——字段-值的映射表" tabindex="-1">Hash——字段-值的映射表 <a class="header-anchor" href="#hash——字段-值的映射表" aria-label="Permalink to &quot;Hash——字段-值的映射表&quot;">​</a></h3><p>一个 key 下挂多个 field-value 对，适合存对象属性：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">HSET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user:1001</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;zhangsan&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> age</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;28&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> city</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;beijing&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">HGET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user:1001</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> name</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # -&gt; &quot;zhangsan&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">HGETALL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user:1001</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # 取出所有 field 和 value</span></span></code></pre></div><p>如果一个用户有几十个属性，用 Hash 存比用多个 String key（<code>user:1001:name</code>、<code>user:1001:age</code>...）更省 key 数量，也更好管理。但 <code>HGETALL</code> 对 field 数量大的 hash 也是 O(n)——几百个 field 可以，几千个就要考虑用 <code>HSCAN</code> 分批取。</p><h3 id="list——按插入顺序排列的字符串列表" tabindex="-1">List——按插入顺序排列的字符串列表 <a class="header-anchor" href="#list——按插入顺序排列的字符串列表" aria-label="Permalink to &quot;List——按插入顺序排列的字符串列表&quot;">​</a></h3><p>底层是双向链表，首尾操作 O(1)，中间操作 O(n)。常用的不是随机存取，而是当队列或栈用：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">LPUSH</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> queue:tasks</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;task1&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;task2&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 左边进</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">RPOP</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> queue:tasks</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                     # 右边出 → FIFO 队列</span></span></code></pre></div><p><code>BLPOP</code>/<code>BRPOP</code> 支持阻塞等待——队列为空时消费者挂起，有新元素时立刻返回，应用层不用轮询：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">BLPOP</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> queue:tasks</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 最多等 5 秒，超时返回 nil</span></span></code></pre></div><p>List 可以当轻量队列用，但它没有消息确认、失败重试、死信队列这些机制。需要这些能力时用 Stream 或专门的消息队列会更合适。</p><h3 id="set——无序不重复的字符串集合" tabindex="-1">Set——无序不重复的字符串集合 <a class="header-anchor" href="#set——无序不重复的字符串集合" aria-label="Permalink to &quot;Set——无序不重复的字符串集合&quot;">​</a></h3><p>底层是哈希表，增删查都是 O(1)。用于去重和交并差运算：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SADD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> article:1:tags</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;redis&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;database&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;nosql&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SISMEMBER</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> article:1:tags</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;redis&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 是否存在</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SINTER</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> article:1:tags</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> article:2:tags</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 两篇文章的共同标签</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SUNION</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> article:1:tags</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> article:2:tags</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 两篇文章的所有标签</span></span></code></pre></div><p><code>SINTER</code>（交集）、<code>SUNION</code>（并集）、<code>SDIFF</code>（差集）的时间复杂度是 O(n)，n 是参与运算的元素总数。集合很大时（几万甚至更多元素）这些运算会阻塞命令处理线程。大数据量下的交并差更适合在从库或离线分析环境跑。</p><h3 id="sorted-set——带权重的有序集合" tabindex="-1">Sorted Set——带权重的有序集合 <a class="header-anchor" href="#sorted-set——带权重的有序集合" aria-label="Permalink to &quot;Sorted Set——带权重的有序集合&quot;">​</a></h3><p>每个元素关联一个 score（浮点数），按 score 排序。底层是跳表 + 哈希表：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ZADD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> leaderboard</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;player1&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 95</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;player2&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 88</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;player3&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ZRANGE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> leaderboard</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> WITHSCORES</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 按 score 升序</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ZREVRANGE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> leaderboard</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> WITHSCORES</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 前 3 名</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ZRANK</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> leaderboard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;player1&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # 排第几（从 0 开始）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ZSCORE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> leaderboard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;player1&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # 查分数</span></span></code></pre></div><p>排行榜是 Sorted Set 的经典场景——插入或更新分数是 O(log n)，查排名也很快。其他用途包括带权重的任务队列、按时间排序的事件流、延迟队列。</p><hr><p>除了这五类，Redis 后续版本还引入了 Stream（带消费者组和消息确认的消息队列）、Geospatial（地理位置索引）、HyperLogLog（基数估算）、Bitmap（位操作）等。Stream 适合需要消息持久化、消费者组和消息确认的场景——相比 List 做队列，Stream 多出了消费者组和多消费者独立消费的能力。</p><h2 id="二、通配键操作" tabindex="-1">二、通配键操作 <a class="header-anchor" href="#二、通配键操作" aria-label="Permalink to &quot;二、通配键操作&quot;">​</a></h2><p>Redis 的 key 没有&quot;表&quot;的概念——整个实例是一个平坦的键空间。键的命名规范是人为约定的，常用 <code>业务:对象:id:属性</code> 这种模式：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">KEYS</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user:1001:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 列出匹配的所有 key</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">EXISTS</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user:1001:name</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # key 是否存在</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">TYPE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user:1001:name</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # 数据类型</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DEL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user:1001:name</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 删除 key</span></span></code></pre></div><p><code>KEYS</code> 在生产环境不安全——它会遍历整个键空间，在上百万个 key 的实例上执行 <code>KEYS *</code> 会让 Redis 阻塞数秒甚至更久。替代方案是 <code>SCAN</code>，游标式迭代，一次只返回一批：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SCAN</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> MATCH</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user:1001:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> COUNT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span></span></code></pre></div><p><code>SCAN</code> 返回一个新的游标和一批 key，反复用新游标调用直到游标回到 0 表示遍历完成。<code>SCAN</code> 遍历的是变化的键空间而不是快照——可能返回重复的 key（遍历过程中有增删），也可能漏掉部分 key（rehash 导致）。所以 <code>SCAN</code> 适合巡检、清理等不需要精确全量的场景，不适合&quot;必须不漏&quot;的需求。</p><h2 id="三、过期策略" tabindex="-1">三、过期策略 <a class="header-anchor" href="#三、过期策略" aria-label="Permalink to &quot;三、过期策略&quot;">​</a></h2><p>Redis 可以对每个 key 设置存活时间：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">EXPIRE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> session:abc123</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3600</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 3600 秒后过期</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">EXPIREAT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> session:abc123</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1717257600</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 在指定 Unix 时间戳过期</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">TTL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> session:abc123</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                   # 还剩多少秒</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">PERSIST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> session:abc123</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # 取消过期，变成永久 key</span></span></code></pre></div><p><code>TTL</code> 返回值：正数表示剩余秒数，<code>-1</code> 表示 key 存在但没有过期时间，<code>-2</code> 表示 key 不存在。</p><p>Redis 的过期删除不是给每个 key 设一个定时器——几百万个定时器开销太大。实际采用两种机制配合：</p><ul><li><strong>惰性删除</strong>：访问一个 key 时检查是否过期，过期了就删掉并返回 nil。如果过期的 key 一直没人访问，它不会被惰性删掉。</li><li><strong>定期删除</strong>：后台每秒执行多次，每次随机抽一批设置了过期时间的 key，把其中过期的删掉。是抽检而非全扫。</li></ul><p>两种机制配合意味着：key 过期和内存释放之间有时间差。恰好这个时间差内的 key 被访问了，会被惰性删除；没有被访问的话会等到下次定期扫描才删。对内存敏感的场景，这个时间差需要心里有数——短时间内可能看到过期 key 仍占着内存。</p><p>缓存 key 一般要有过期时间。没有过期时间的缓存，后面容易变成&quot;没人敢删&quot;的历史数据。会话、验证码、临时锁这类 key 更是要带 TTL。</p><h2 id="四、lua-脚本和原子操作" tabindex="-1">四、Lua 脚本和原子操作 <a class="header-anchor" href="#四、lua-脚本和原子操作" aria-label="Permalink to &quot;四、Lua 脚本和原子操作&quot;">​</a></h2><p>Redis 执行 Lua 脚本时，整个脚本被当作一个原子操作——脚本执行期间其他命令无法插入。适合&quot;读-判断-写&quot;这类不想被中途打断的场景：</p><div class="language-lua vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">lua</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 释放锁的正确方式：先检查 value 是不是自己的，再删</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 如果不用 Lua，GET + DEL 之间不是原子的，可能误删别人的锁</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> redis.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">call</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;GET&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, KEYS[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ARGV[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">then</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> redis.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">call</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;DEL&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, KEYS[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">])</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">else</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">end</span></span></code></pre></div><p>用 <code>EVAL</code> 执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> EVAL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;if redis.call(&#39;GET&#39;, KEYS[1]) == ARGV[1] then return redis.call(&#39;DEL&#39;, KEYS[1]) else return 0 end&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lock:order:1001</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> thread-5</span></span></code></pre></div><p><code>EVALSHA</code> 可以把脚本缓存在 Redis 里，后续只传 SHA1 不传完整脚本，高频调用时减少网络传输量。</p><p>Lua 脚本的原子性是把双刃剑：能保证操作不被打断，但如果脚本执行时间太长（比如循环操作大量 key），整条命令处理线程都会被它占用。Lua 脚本里要避免循环次数不确定或者集合大小不确定的操作。</p><h2 id="五、发布订阅" tabindex="-1">五、发布订阅 <a class="header-anchor" href="#五、发布订阅" aria-label="Permalink to &quot;五、发布订阅&quot;">​</a></h2><p>Redis 的 Pub/Sub 是消息广播机制——发布者往 channel 发消息，订阅了该 channel 的所有客户端都会收到：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SUBSCRIBE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> news:system</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # 订阅频道</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">PUBLISH</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> news:system</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;server down&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 发消息</span></span></code></pre></div><p>Pub/Sub 的消息是&quot;即发即忘&quot;——没有持久化，没有确认，没有消费者组。订阅者离线期间的消息就丢了。它适合通知性质的消息（&quot;配置变了，请重新加载&quot;），不适合需要可靠投递的业务消息。</p><h2 id="六、基础状态查看" tabindex="-1">六、基础状态查看 <a class="header-anchor" href="#六、基础状态查看" aria-label="Permalink to &quot;六、基础状态查看&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INFO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 版本、进程、运行时间</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INFO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clients</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # 客户端连接情况</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INFO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 内存使用情况</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INFO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stats</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 命令、连接、命中率等统计</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INFO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> persistence</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # RDB/AOF 持久化状态</span></span></code></pre></div><p>几个基础指标：</p><table tabindex="0"><thead><tr><th>指标</th><th>含义</th></tr></thead><tbody><tr><td><code>used_memory</code></td><td>Redis 分配器统计的内存</td></tr><tr><td><code>connected_clients</code></td><td>当前客户端连接数</td></tr><tr><td><code>blocked_clients</code></td><td>阻塞等待的客户端数（比如 BLPOP 等待）</td></tr><tr><td><code>expired_keys</code></td><td>已过期删除的 key 累计数</td></tr><tr><td><code>evicted_keys</code></td><td>因内存达上限被淘汰的 key 累计数</td></tr><tr><td><code>keyspace_hits/misses</code></td><td>缓存命中和未命中次数</td></tr></tbody></table><p><code>evicted_keys</code> 和 <code>expired_keys</code> 的区别：前者是因为内存满了被 maxmemory 策略踢掉的，后者是到期后被过期机制删掉的。<code>evicted_keys</code> 持续增长说明内存不够用——要么扩内存，要么清理无用 key，要么调整淘汰策略。</p><h2 id="七、简单性能压测" tabindex="-1">七、简单性能压测 <a class="header-anchor" href="#七、简单性能压测" aria-label="Permalink to &quot;七、简单性能压测&quot;">​</a></h2><p><code>redis-benchmark</code> 是 Redis 自带的压测工具，用来对单机 Redis 做基本的吞吐和延迟摸底——不是性能调优的最终结论，而是&quot;这台机器上的这个 Redis 实例大概是什么水平&quot;：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-benchmark</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 127.0.0.1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 6379</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set,get</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -q</span></span></code></pre></div><p><code>-c 100</code> 是 100 个并发连接，<code>-t</code> 指定只测 SET 和 GET，<code>-n 100000</code> 总共发 10 万个请求，<code>-q</code> 只输出简要结果。输出示例：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SET: 95238.10 requests per second</span></span>
<span class="line"><span>GET: 102040.82 requests per second</span></span></code></pre></div><p>这些数字在普通服务器上（几十个并发连接、小 Value）大概在 8-12 万 QPS 量级。实际业务 QPS 受 Value 大小、网络延迟、Pipeline 使用等因素影响。压测时要在和生产环境接近的硬件和网络条件上跑，否则数据没参考价值。</p><p><code>--pipeline</code> 参数模拟批量发送命令，用来测单连接上的吞吐上限：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-benchmark</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 127.0.0.1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 6379</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -P</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 16</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -q</span></span></code></pre></div><p><code>-P 16</code> 表示一次发送 16 条命令，减少 RTT 的影响。Pipeline 下 QPS 远高于单条发送，因为大量减少了网络往返开销。</p>`,76)])])}const c=i(h,[["render",n]]);export{o as __pageData,c as default};
